122→	Array<{
123→		session_id: string;
124→		project_path: string;
125→		repository: string;
126→		tag: string;
127→		user_id: string;
128→		organization_id: string;
129→	}>
130→> {
131→	const start = Date.now();
132→	while (Date.now() - start < timeoutMs) {
133→		try {
134→			const results = await executor.query<{
135→				session_id: string;
136→				project_path: string;
137→				repository: string;
138→				tag: string;
139→				user_id: string;
140→				organization_id: string;
141→			}>(
142→				`SELECT session_id, project_path, repository, tag, user_id, organization_id FROM rudel.claude_sessions WHERE session_id = '${sessionId}' LIMIT 1`,
143→			);
144→			if (results.length > 0) return results;
145→		} catch {
146→			// Transient ClickHouse errors (e.g. S3 storage) - retry
147→		}
148→		await new Promise((r) => setTimeout(r, intervalMs));
149→	}
150→	return [];
