 41→async function waitForQuery<T>(
 42→	query: string,
 43→	timeoutMs = 30000,
 44→	intervalMs = 2000,
 45→): Promise<T[]> {
 46→	const start = Date.now();
 47→	while (Date.now() - start < timeoutMs) {
 48→		try {
 49→			const results = await executor.query<T>(query);
 50→			if (results.length > 0) return results;
 51→		} catch {
 52→			// Transient ClickHouse errors (e.g. S3 storage) - retry
 53→		}
 54→		await new Promise((r) => setTimeout(r, intervalMs));
 55→	}
 56→	return [];
 57→}
 58→
 59→async function insertWithRetry(
 60→	fn: () => Promise<void>,
 61→	queryFn: () => Promise<unknown[]>,
 62→	maxAttempts = 5,
 63→): Promise<unknown[]> {
 64→	for (let attempt = 0; attempt < maxAttempts; attempt++) {
 65→		try {
 66→			await fn();
 67→		} catch (error) {
 68→			// Retry on transient ClickHouse errors (e.g. INSERT race conditions)
 69→			if (attempt === maxAttempts - 1) throw error;
 70→			await new Promise((r) => setTimeout(r, 2000 * 2 ** attempt));
 71→			continue;
 72→		}
 73→		const results = await queryFn();
 74→		if (results.length > 0) return results;
 75→	}
 76→	return [];
 77→}
