216→async function promptForOtp(): Promise<string> {
217→	const rl = createInterface({ input: stdin, output: stdout });
218→	try {
219→		const otp = await rl.question("Enter npm OTP to publish: ");
220→		const trimmed = otp.trim();
221→		if (trimmed.length === 0) {
222→			fail("No OTP provided. Publish cancelled.");
223→		}
224→		return trimmed;
225→	} finally {
226→		rl.close();
227→	}
