261→function shellQuote(value: string): string {
262→	if (/^[A-Za-z0-9_./:-]+$/.test(value)) {
263→		return value;
264→	}
265→	return `'${value.replaceAll("'", "'\\''")}'`;
266→}
267→
268→function logLine(message: string): void {
269→	process.stdout.write(`${message}\n`);
270→}
271→
272→function fail(message: string): never {
273→	logLine(`ERROR: ${message}`);
274→	process.exit(1);
275→}
276→
277→await main();
