 65→function spawnServer(env: Record<string, string | undefined>) {
 66→	const proc = Bun.spawn(["bun", "apps/api/src/index.ts"], {
 67→		cwd: MONOREPO_ROOT,
 68→		stdout: "pipe",
 69→		stderr: "pipe",
 70→		env,
 71→	});
 72→	proc.unref();
 73→	return proc;
