131→/**
132→ * Poll the server until it responds to a GET request.
133→ * Retries every 200ms for up to 10s.
134→ */
135→async function waitForReady(baseUrl: string): Promise<void> {
136→	const deadline = Date.now() + 10_000;
137→	while (Date.now() < deadline) {
138→		try {
139→			const res = await fetch(`${baseUrl}/health`, {
140→				signal: AbortSignal.timeout(2000),
141→			});
142→			if (res.ok) return;
143→		} catch {
144→			// Connection refused or timeout — retry
145→		}
146→		await Bun.sleep(200);
147→	}
148→	throw new Error(
149→		`Server at ${baseUrl} did not respond within 10s after port was detected`,
150→	);
151→}
